import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Trait {
  FAST_REPRODUCTION = "Fast Reproduction",
  TOXIN_RESISTANCE = "Toxin Resistance",
  HIGH_YIELD = "High Yield",
  BIO_LUMINESCENCE = "Bio-luminescence", // Neutral/Desirable
  OXYGEN_DEPLETION = "Oxygen Depletion", // Undesirable
  SLOW_GROWTH = "Slow Growth", // Undesirable
  INVASIVE = "Invasive", // Undesirable
  NONE = "None"
}

export interface Microbe {
  id: string;
  name: string;
  temp: number; // 0-100
  salinity: number; // 0-100
  ph: number; // 0-14 mapped to 0-100 scale often, but let's stick to 0-14 for realism or 0-100 for game simplicity. Let's use 0-100 generic units.
  trait: Trait;
  type: 'Bacteria' | 'Fungi' | 'Algae';
}

export interface Range {
  min: number;
  max: number;
}

export interface SiteRequirements {
  temp: Range;
  salinity: Range;
  ph: Range;
  desirable: Trait[];
  undesirable: Trait[];
}

export interface Site {
  id: number;
  name: string;
  description: string;
  requirements: SiteRequirements;
  nextSiteClue: string;
}

export enum GameStage {
  INTRO = 'INTRO',
  PROFILING = 'PROFILING',
  CATEGORIZATION = 'CATEGORIZATION', // The Sieve
  PROSPECTING = 'PROSPECTING', // The Choice
  TREATMENT = 'TREATMENT', // Final Selection
  SCORING = 'SCORING',
  GAME_OVER = 'GAME_OVER'
}

export interface ScoringResult {
  avgTemp: number;
  avgSalinity: number;
  avgPh: number;
  desirableCount: number;
  undesirableCount: number;
  score: number;
  passed: boolean;
  breakdown: string[];
}

import { Microbe, Site, Trait, Range, ScoringResult } from '../types';

const MICROBE_NAMES_PREFIX = ['Pseudo', 'Cyano', 'Myco', 'Halo', 'Thio', 'Nitro', 'Vibrio', 'Actino'];
const MICROBE_NAMES_SUFFIX = ['bacter', 'coccus', 'monas', 'spirillum', 'bacillus', 'myces', 'plankton'];

export const generateMicrobe = (id: string, bias?: Partial<Microbe>): Microbe => {
  const prefix = MICROBE_NAMES_PREFIX[Math.floor(Math.random() * MICROBE_NAMES_PREFIX.length)];
  const suffix = MICROBE_NAMES_SUFFIX[Math.floor(Math.random() * MICROBE_NAMES_SUFFIX.length)];

  const types: ('Bacteria' | 'Fungi' | 'Algae')[] = ['Bacteria', 'Fungi', 'Algae'];
  const traits = [
    Trait.FAST_REPRODUCTION, Trait.TOXIN_RESISTANCE, Trait.HIGH_YIELD, 
    Trait.BIO_LUMINESCENCE, Trait.OXYGEN_DEPLETION, Trait.SLOW_GROWTH, Trait.INVASIVE, Trait.NONE
  ];

  // Weighted random for traits to ensure mix of good/bad
  const randomTrait = Math.random() > 0.3 
    ? traits[Math.floor(Math.random() * 4)] // Good/Neutral
    : traits[Math.floor(Math.random() * 3) + 4]; // Bad

  return {
    id,
    name: `${prefix}${suffix}-${Math.floor(Math.random() * 999)}`,
    type: types[Math.floor(Math.random() * types.length)],
    temp: Math.floor(Math.random() * 80) + 10,
    salinity: Math.floor(Math.random() * 80) + 10,
    ph: Math.floor(Math.random() * 60) + 20, // Normalized 20-80 roughly
    trait: randomTrait,
    ...bias
  };
};

export const generateSites = (): Site[] => {
  return [
    {
      id: 1,
      name: "Coastal Estuary (Site 1)",
