import React, { useState, useEffect } from 'react';
import { Microbe, Site } from '../types';
import MicrobeCard from './MicrobeCard';
import { generateMicrobe } from '../services/gameLogic';
import { Archive, ArrowRight, Save, Trash2 } from 'lucide-react';

interface Stage2Props {
  onComplete: (kept: Microbe[], saved: Microbe[]) => void;
  siteId: number;
}

const Stage2Sieve: React.FC<Stage2Props> = ({ onComplete, siteId }) => {
  const [queue, setQueue] = useState<Microbe[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [kept, setKept] = useState<Microbe[]>([]);
  const [saved, setSaved] = useState<Microbe[]>([]);

  useEffect(() => {
    // Generate 10 microbes for screening
    const newQueue = Array.from({ length: 10 }).map((_, i) => 
        generateMicrobe(`sieve-${siteId}-${i}`)
    );
    setQueue(newQueue);
  }, [siteId]);

  const handleAction = (action: 'KEEP' | 'SAVE' | 'REJECT') => {
    const currentMicrobe = queue[currentIndex];

    if (action === 'KEEP') {
        setKept([...kept, currentMicrobe]);
    } else if (action === 'SAVE') {
        setSaved([...saved, currentMicrobe]);
    }
    // REJECT does nothing but move index

    if (currentIndex < queue.length - 1) {
        setCurrentIndex(currentIndex + 1);
    } else {
        // Finished
        // We pass the final state, adding the kept to the new kept state inside the handler
        const finalKept = action === 'KEEP' ? [...kept, currentMicrobe] : kept;
        const finalSaved = action === 'SAVE' ? [...saved, currentMicrobe] : saved;
        onComplete(finalKept, finalSaved);
    }
  };

  const currentMicrobe = queue[currentIndex];

  if (!currentMicrobe) return <div className="text-white">Loading Sieve...</div>;

  return (
    <div className="w-full max-w-2xl mx-auto">
        <div className="text-center mb-6">
            <h2 className="text-2xl font-bold text-white mb-2">Stage 2: The Sieve</h2>
            <p className="text-slate-400 text-sm">Analyze microbes sequentially. Decisions are final.</p>
            <div className="mt-4 flex justify-center gap-4 text-sm font-mono">
                <span className="text-teal-400">Kept: {kept.length}</span>
                <span className="text-slate-500">Remaining: {queue.length - currentIndex}</span>
                <span className="text-amber-400">Saved for Later: {saved.length}</span>
            </div>
        </div>

        <div className="relative h-96 w-full max-w-sm mx-auto mb-8 perspective-1000">
            <div className="w-full h-full animate-in zoom-in duration-300">
                 <MicrobeCard microbe={currentMicrobe} />
            </div>
        </div>

        <div className="grid grid-cols-3 gap-4">
             <button 
                onClick={() => handleAction('KEEP')}
                className="flex flex-col items-center justify-center p-4 bg-teal-900/30 border border-teal-600/50 rounded-xl hover:bg-teal-900/50 transition-colors group"
            >
                <Archive className="w-6 h-6 text-teal-400 mb-2 group-hover:scale-110 transition-transform" />
                <span className="text-teal-200 font-bold">Keep (S1)</span>
                <span className="text-xs text-teal-500 mt-1">Add to current pool</span>
            </button>

            <button 
                onClick={() => handleAction('SAVE')}
                className="flex flex-col items-center justify-center p-4 bg-amber-900/30 border border-amber-600/50 rounded-xl hover:bg-amber-900/50 transition-colors group"
            >
                <Save className="w-6 h-6 text-amber-400 mb-2 group-hover:scale-110 transition-transform" />
                <span className="text-amber-200 font-bold">Save (Next)</span>
                <span className="text-xs text-amber-500 mt-1">Send to Site {siteId + 1}</span>
            </button>

            <button 
                onClick={() => handleAction('REJECT')}
                className="flex flex-col items-center justify-center p-4 bg-rose-900/30 border border-rose-600/50 rounded-xl hover:bg-rose-900/50 transition-colors group"
            >
                <Trash2 className="w-6 h-6 text-rose-400 mb-2 group-hover:scale-110 transition-transform" />
                <span className="text-rose-200 font-bold">Reject</span>
                <span className="text-xs text-rose-500 mt-1">Discard sample</span>
            </button>
        </div>
    </div>
  );
};

export default Stage2Sieve;

import React, { useState, useEffect } from 'react';
import { Microbe } from '../types';
import MicrobeCard from './MicrobeCard';
import { generateMicrobe } from '../services/gameLogic';

interface Props {
  currentPoolSize: number;
  onComplete: (added: Microbe[]) => void;
}

const Stage3Prospecting: React.FC<Props> = ({ currentPoolSize, onComplete }) => {
  const TARGET_POOL_SIZE = 10;
  const NEEDED = Math.max(0, TARGET_POOL_SIZE - currentPoolSize);

  const [round, setRound] = useState(0);
  const [options, setOptions] = useState<Microbe[]>([]);
  const [selected, setSelected] = useState<Microbe[]>([]);

  useEffect(() => {
    // Generate 3 options for the current round
    if (round < NEEDED) {
        setOptions([
            generateMicrobe(`pros-${round}-1`),
            generateMicrobe(`pros-${round}-2`),
            generateMicrobe(`pros-${round}-3`),
        ]);
    } else if (round === NEEDED && NEEDED > 0) {
        onComplete(selected);
    } else if (NEEDED === 0) {
        onComplete([]);
    }
  }, [round, NEEDED]);

  const handleSelect = (m: Microbe) => {
    const newSelected = [...selected, m];
    setSelected(newSelected);
    setRound(round + 1);
  };

  if (NEEDED === 0) return null; // Should have been handled by effect, but safe guard
  if (round >= NEEDED) return <div className="text-white text-center text-xl animate-pulse">Analyzing final pool composition...</div>;

  return (
    <div className="w-full max-w-5xl mx-auto">
      <div className="text-center mb-8">
        <h2 className="text-2xl font-bold text-white">Stage 3: Prospecting</h2>
        <p className="text-slate-400">You need {NEEDED} more microbes. Pick 1 of 3 for Round {round + 1}/{NEEDED}.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {options.map((m) => (
            <div 
                key={m.id} 
                className="cursor-pointer transform hover:-translate-y-2 transition-transform duration-200 relative group"
                onClick={() => handleSelect(m)}
            >
                <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-teal-500 text-slate-900 px-3 py-1 rounded-full text-xs font-bold opacity-0 group-hover:opacity-100 transition-opacity z-10">
                    SELECT
                </div>
                <div className="h-full">
                    <MicrobeCard microbe={m} />
                </div>
            </div>
        ))}
      </div>
    </div>
  );
};

export default Stage3Prospecting;

import React, { useState } from 'react';
import { Microbe, Site } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine } from 'recharts';
import { Check, AlertTriangle } from 'lucide-react';

interface Props {
  pool: Microbe[];
  site: Site;
  onComplete: (selected: Microbe[]) => void;
}

const Stage4Treatment: React.FC<Props> = ({ pool, site, onComplete }) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const toggleSelection = (id: string) => {
    if (selectedIds.includes(id)) {
      setSelectedIds(selectedIds.filter(i => i !== id));
    } else {
      if (selectedIds.length < 3) {
        setSelectedIds([...selectedIds, id]);
      }
    }
  };

  const selectedMicrobes = pool.filter(m => selectedIds.includes(m.id));

  // Real-time calculation for visualization
  const currentStats = {
      temp: selectedMicrobes.length ? selectedMicrobes.reduce((a,b) => a + b.temp, 0) / selectedMicrobes.length : 0,
      salinity: selectedMicrobes.length ? selectedMicrobes.reduce((a,b) => a + b.salinity, 0) / selectedMicrobes.length : 0,
      ph: selectedMicrobes.length ? selectedMicrobes.reduce((a,b) => a + b.ph, 0) / selectedMicrobes.length : 0,
  };

