                selectedIds.length === 3
                    ? 'bg-teal-500 hover:bg-teal-400 text-slate-900 shadow-lg shadow-teal-500/20'
                    : 'bg-slate-700 text-slate-500 cursor-not-allowed'
            }`}
        >
