        </button>
      </div>
    </div>
  );
};

export default Stage4Treatment;

import React, { useState, useEffect } from 'react';
import { GameStage, Site, Microbe, ScoringResult } from './types';
import { generateSites, calculateScore } from './services/gameLogic';
import Stage1Profiling from './components/Stage1Profiling';
import Stage2Sieve from './components/Stage2Sieve';
import Stage3Prospecting from './components/Stage3Prospecting';
import Stage4Treatment from './components/Stage4Treatment';
import { Clock, Waves, Award, Play } from 'lucide-react';

const App: React.FC = () => {
  const [sites] = useState<Site[]>(generateSites());
  const [currentSiteIndex, setCurrentSiteIndex] = useState(0);
  const [stage, setStage] = useState<GameStage>(GameStage.INTRO);

  // Pools
  const [currentPool, setCurrentPool] = useState<Microbe[]>([]);
  const [nextSitePool, setNextSitePool] = useState<Microbe[]>([]);

  // Timer (30 mins = 1800s)
  const [timeLeft, setTimeLeft] = useState(1800);
  const [isActive, setIsActive] = useState(false);

  // Score Tracking
  const [totalScore, setTotalScore] = useState(0);
  const [lastResult, setLastResult] = useState<ScoringResult | null>(null);

  useEffect(() => {
    let interval: any;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((time) => time - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setStage(GameStage.GAME_OVER);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const startGame = () => {
    setIsActive(true);
    setStage(GameStage.PROFILING);
  };

  const handleStage1Complete = () => {
    setStage(GameStage.CATEGORIZATION);
  };

  const handleStage2Complete = (kept: Microbe[], saved: Microbe[]) => {
    setCurrentPool([...currentPool, ...kept]);
    setNextSitePool([...nextSitePool, ...saved]); // Accumulate for next site
    setStage(GameStage.PROSPECTING);
  };

  const handleStage3Complete = (added: Microbe[]) => {
    setCurrentPool(prev => [...prev, ...added]);
    setStage(GameStage.TREATMENT);
  };

  const handleStage4Complete = (selected: Microbe[]) => {
    const result = calculateScore(selected, sites[currentSiteIndex]);
    setLastResult(result);
    setTotalScore(prev => prev + result.score);
    setStage(GameStage.SCORING);
  };

  const nextSite = () => {
    if (currentSiteIndex < sites.length - 1) {
        setCurrentSiteIndex(prev => prev + 1);
        setCurrentPool([...nextSitePool]); // Import saved microbes
        setNextSitePool([]); // Clear stash
        setStage(GameStage.PROFILING);
    } else {
        setStage(GameStage.GAME_OVER);
        setIsActive(false);
    }
  };

  const currentSite = sites[currentSiteIndex];
  const followingSite = currentSiteIndex < sites.length - 1 ? sites[currentSiteIndex + 1] : undefined;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-teal-500 selection:text-white">
      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-teal-500/10 p-2 rounded-lg">
                    <Waves className="text-teal-400 w-6 h-6" />
                </div>
                <div>
                    <h1 className="font-bold text-white leading-tight">Sea Wolf</h1>
                    <div className="text-xs text-slate-500 font-mono">SIMULATION_V3.1</div>
                </div>
            </div>

            {stage !== GameStage.INTRO && stage !== GameStage.GAME_OVER && (
                <div className="flex items-center gap-8">
                    <div className="text-center">
                        <span className="text-xs text-slate-500 uppercase block">Current Site</span>
                        <span className="text-teal-300 font-bold">{currentSiteIndex + 1} / {sites.length}</span>
                    </div>
                    <div className="text-center">
                        <span className="text-xs text-slate-500 uppercase block">Score</span>
                        <span className="text-white font-mono font-bold">{totalScore}</span>
                    </div>
                    <div className={`flex items-center gap-2 px-4 py-2 rounded-full border ${timeLeft < 300 ? 'bg-red-900/20 border-red-800 text-red-400 animate-pulse' : 'bg-slate-800 border-slate-700 text-teal-400'}`}>
                        <Clock className="w-4 h-4" />
                        <span className="font-mono font-bold text-lg">{formatTime(timeLeft)}</span>
                    </div>
                </div>
            )}
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8">

        {stage === GameStage.INTRO && (
             <div className="flex flex-col items-center justify-center min-h-[60vh] text-center max-w-2xl mx-auto">
                <div className="mb-8 relative">
                    <div className="absolute inset-0 bg-teal-500 blur-3xl opacity-20 rounded-full"></div>
                    <Waves className="w-24 h-24 text-teal-400 relative z-10" />
                </div>
                <h1 className="text-5xl font-bold text-white mb-6">Sea Wolf Simulator</h1>
                <p className="text-lg text-slate-400 mb-8 leading-relaxed">
                    Welcome to the Ocean Treatment Optimization assessment. You will manage 3 microbial treatment sites.
                    Balance temperature, salinity, and pH while optimizing for genetic traits. 
                    <br/><br/>
                    <strong className="text-teal-400">Time Limit: 30 Minutes.</strong>
                </p>
                <button 
                    onClick={startGame}
                    className="group bg-teal-500 hover:bg-teal-400 text-slate-900 px-8 py-4 rounded-xl font-bold text-xl flex items-center gap-3 transition-all shadow-lg shadow-teal-500/20 hover:scale-105"
                >
                    <Play className="w-6 h-6 fill-current" />
                    Initialize Simulation
                </button>
             </div>
        )}

        {stage === GameStage.PROFILING && (
            <Stage1Profiling site={currentSite} onComplete={handleStage1Complete} />
        )}

        {stage === GameStage.CATEGORIZATION && (
            <Stage2Sieve 
                site={currentSite} 
                nextSite={followingSite}
                onComplete={handleStage2Complete} 
            />
        )}

        {stage === GameStage.PROSPECTING && (
            <Stage3Prospecting 
                currentPoolSize={currentPool.length} 
                site={currentSite}
                onComplete={handleStage3Complete} 
            />
        )}

        {stage === GameStage.TREATMENT && (
            <Stage4Treatment pool={currentPool} site={currentSite} onComplete={handleStage4Complete} />
        )}

        {stage === GameStage.SCORING && lastResult && (
            <div className="max-w-2xl mx-auto bg-slate-900 border border-slate-700 rounded-xl p-8 text-center animate-in zoom-in duration-300">
                <Award className={`w-16 h-16 mx-auto mb-6 ${lastResult.passed ? 'text-green-400' : 'text-amber-400'}`} />
                <h2 className="text-3xl font-bold text-white mb-2">{lastResult.passed ? 'Site Treated Successfully' : 'Treatment Sub-Optimal'}</h2>
                <div className="text-6xl font-black text-white mb-8 font-mono">{lastResult.score}<span className="text-2xl text-slate-500">/100</span></div>

                <div className="bg-slate-800 rounded-lg p-6 mb-8 text-left space-y-2">
                    {lastResult.breakdown.map((line, i) => (
                        <div key={i} className="flex items-center gap-3">
                            <div className={`w-2 h-2 rounded-full ${line.includes('+20') ? 'bg-green-500' : 'bg-red-500'}`}></div>
                            <span className="text-slate-300">{line}</span>
                        </div>
                    ))}
                </div>

                <button 
                    onClick={nextSite}
                    className="bg-teal-500 hover:bg-teal-400 text-slate-900 px-8 py-3 rounded-lg font-bold text-lg w-full transition-colors"
                >
                    {currentSiteIndex < sites.length - 1 ? "Proceed to Next Site" : "Finalize Report"}
                </button>
            </div>
        )}

        {stage === GameStage.GAME_OVER && (
            <div className="flex flex-col items-center justify-center min-h-[50vh] text-center">
                <h2 className="text-4xl font-bold text-white mb-4">Simulation Complete</h2>
                <p className="text-slate-400 mb-8">Final Aggregate Score</p>
                <div className="text-8xl font-black text-teal-400 mb-8">{totalScore}</div>
                <p className="text-slate-500 max-w-md mx-auto">
                    The Sea Wolf protocol has concluded. Your results have been logged for the assessment board.
                </p>
                <button onClick={() => window.location.reload()} className="mt-8 text-slate-400 hover:text-white underline">
                    Restart Simulation
                </button>
            </div>
        )}

      </main>
    </div>
  );
};

export default App;

import { Microbe, Site, Trait, Range, ScoringResult } from '../types';

const MICROBE_NAMES_PREFIX = ['Pseudo', 'Cyano', 'Myco', 'Halo', 'Thio', 'Nitro', 'Vibrio', 'Actino'];
const MICROBE_NAMES_SUFFIX = ['bacter', 'coccus', 'monas', 'spirillum', 'bacillus', 'myces', 'plankton'];

export const generateMicrobe = (id: string, bias?: Partial<Microbe>): Microbe => {
  const prefix = MICROBE_NAMES_PREFIX[Math.floor(Math.random() * MICROBE_NAMES_PREFIX.length)];
  const suffix = MICROBE_NAMES_SUFFIX[Math.floor(Math.random() * MICROBE_NAMES_SUFFIX.length)];

  const types: ('Bacteria' | 'Fungi' | 'Algae')[] = ['Bacteria', 'Fungi', 'Algae'];
  const traits = [
    Trait.FAST_REPRODUCTION, Trait.TOXIN_RESISTANCE, Trait.HIGH_YIELD, 
    Trait.BIO_LUMINESCENCE, Trait.OXYGEN_DEPLETION, Trait.SLOW_GROWTH, Trait.INVASIVE, Trait.NONE
  ];

  // Weighted random for traits to ensure mix of good/bad
  const randomTrait = Math.random() > 0.3 
    ? traits[Math.floor(Math.random() * 4)] // Good/Neutral
    : traits[Math.floor(Math.random() * 3) + 4]; // Bad

  return {
    id,
    name: `${prefix}${suffix}-${Math.floor(Math.random() * 999)}`,
    type: types[Math.floor(Math.random() * types.length)],
    temp: Math.floor(Math.random() * 10) + 1, // 1-10 Scale
    salinity: Math.floor(Math.random() * 10) + 1, // 1-10 Scale
    ph: Math.floor(Math.random() * 10) + 1, // 1-10 Scale
    trait: randomTrait,
    ...bias
  };
};

export const generateSites = (): Site[] => {
  return [
    {
      id: 1,
      name: "Coastal Estuary (Site 1)",
      description: "A shallow mixing zone. Needs moderate temp and low salinity.",
      requirements: {
        temp: { min: 4, max: 6 },
        salinity: { min: 2, max: 4 },
        ph: { min: 6, max: 8 },
        desirable: [Trait.FAST_REPRODUCTION],
        undesirable: [Trait.OXYGEN_DEPLETION]
      },
      nextSiteClue: "Deep Sea Vent"
    },
    {
      id: 2,
      name: "Deep Sea Vent (Site 2)",
      description: "High pressure environment. Extreme heat and salinity.",
      requirements: {
        temp: { min: 8, max: 10 },
        salinity: { min: 8, max: 10 },
        ph: { min: 3, max: 5 },
        desirable: [Trait.TOXIN_RESISTANCE],
        undesirable: [Trait.SLOW_GROWTH]
      },
      nextSiteClue: "Bleached Coral Reef"
    },
    {
      id: 3,
      name: "Bleached Coral Reef (Site 3)",
      description: "Delicate ecosystem recovering from acidification.",
      requirements: {
        temp: { min: 5, max: 7 },
        salinity: { min: 4, max: 6 },
        ph: { min: 7, max: 9 },
        desirable: [Trait.HIGH_YIELD, Trait.BIO_LUMINESCENCE],
        undesirable: [Trait.INVASIVE]
      },
      nextSiteClue: "Simulation Complete."
    }
  ];
};

export const calculateScore = (selected: Microbe[], site: Site): ScoringResult => {
  if (selected.length === 0) {
    return {
      avgTemp: 0, avgSalinity: 0, avgPh: 0, desirableCount: 0, undesirableCount: 0, score: 0, passed: false, breakdown: []
    }
  }

  const avgTemp = selected.reduce((acc, m) => acc + m.temp, 0) / selected.length;
  const avgSalinity = selected.reduce((acc, m) => acc + m.salinity, 0) / selected.length;
  const avgPh = selected.reduce((acc, m) => acc + m.ph, 0) / selected.length;

  let score = 0;
  const breakdown: string[] = [];

  // 1. Temp (20 pts)
  if (avgTemp >= site.requirements.temp.min && avgTemp <= site.requirements.temp.max) {
    score += 20;
    breakdown.push(`Temperature: ${avgTemp.toFixed(1)} (Target ${site.requirements.temp.min}-${site.requirements.temp.max}) [+20]`);
  } else {
    breakdown.push(`Temperature: ${avgTemp.toFixed(1)} (Target ${site.requirements.temp.min}-${site.requirements.temp.max}) [0]`);
  }

  // 2. Salinity (20 pts)
  if (avgSalinity >= site.requirements.salinity.min && avgSalinity <= site.requirements.salinity.max) {
    score += 20;
    breakdown.push(`Salinity: ${avgSalinity.toFixed(1)} (Target ${site.requirements.salinity.min}-${site.requirements.salinity.max}) [+20]`);
  } else {
    breakdown.push(`Salinity: ${avgSalinity.toFixed(1)} (Target ${site.requirements.salinity.min}-${site.requirements.salinity.max}) [0]`);
  }

  // 3. pH (20 pts)
  if (avgPh >= site.requirements.ph.min && avgPh <= site.requirements.ph.max) {
    score += 20;
    breakdown.push(`pH Level: ${avgPh.toFixed(1)} (Target ${site.requirements.ph.min}-${site.requirements.ph.max}) [+20]`);
  } else {
    breakdown.push(`pH Level: ${avgPh.toFixed(1)} (Target ${site.requirements.ph.min}-${site.requirements.ph.max}) [0]`);
  }

  // 4. Desirable (20 pts)
  const desCount = selected.filter(m => site.requirements.desirable.includes(m.trait)).length;
  if (desCount >= 1) {
    score += 20;
    breakdown.push(`Desirable Trait: Found ${desCount} (+20)`);
  } else {
    breakdown.push("Desirable Trait: None Found (0)");
  }

  // 5. Undesirable (20 pts)
  const undesCount = selected.filter(m => site.requirements.undesirable.includes(m.trait)).length;
  if (undesCount === 0) {
    score += 20;
    breakdown.push("Undesirable Trait: None Present (+20)");
  } else {
    breakdown.push(`Undesirable Trait: Found ${undesCount} (0)`);
  }

  return {
    avgTemp,
    avgSalinity,
    avgPh,
    desirableCount: desCount,
    undesirableCount: undesCount,
    score,
    passed: score >= 60,
    breakdown
  };
};

