                        : 'bg-slate-800 text-slate-500 cursor-not-allowed'
                }`}
            >
                {isReady ? (
                    <div className="flex items-center gap-2">
                        <Search className="w-5 h-5 animate-spin" />
                        Running Database Scan...
                    </div>
                ) : (
                    <>Initiate Scan ({selectedFilters.length}/2)</>
                )}
            </button>
        </div>
      </div>
    </div>
  );
};

